from flask import Flask, jsonify, request
from solana.rpc.api import Client
from solana.publickey import PublicKey
from solders.signature import Signature
import json
import traceback

app = Flask(__name__)

# Connect to Solana devnet
client = Client("https://api.devnet.solana.com")

@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Resource not found"}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({"error": "Internal server error"}), 500

@app.route('/status')
def get_status():
    try:
        # Get network status
        health = client.get_health()
        slot_info = client.get_slot()
        cluster_nodes = client.get_cluster_nodes()
        version = client.get_version()

        return jsonify({
            "status": "online" if health.value == "ok" else "offline",
            "network": "devnet",
            "current_slot": slot_info.value,
            "node_count": len(cluster_nodes.value) if cluster_nodes.value else 0,
            "version": version.value.get("solana-core", "unknown") if version.value else "unknown"
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/block/<int:slot_number>')
def get_block(slot_number):
    try:
        # Get block by slot number
        block = client.get_block(slot_number)

        if not block.value:
            return jsonify({"error": "Block not found"}), 404

        block_data = block.value

        return jsonify({
            "blockhash": str(block_data.blockhash),
            "parent_slot": block_data.parent_slot,
            "previous_blockhash": str(block_data.previous_blockhash),
            "block_height": block_data.block_height,
            "block_time": block_data.block_time
        })
    except Exception as e:
        if "not found" in str(e).lower() or "does not exist" in str(e).lower():
            return jsonify({"error": "Block not found"}), 404
        return jsonify({"error": str(e)}), 500

@app.route('/transaction/<signature>')
def get_transaction(signature):
    try:
        # Get transaction by signature
        tx_sig = Signature.from_string(signature)
        tx = client.get_transaction(tx_sig)

        if not tx.value:
            return jsonify({"error": "Transaction not found"}), 404

        tx_data = tx.value

        # Extract token transfers from transaction
        token_transfers = []
        if hasattr(tx_data, 'meta') and tx_data.meta and hasattr(tx_data.meta, 'post_token_balances'):
            # This is a simplified token transfer extraction
            # In a real implementation, you'd parse the instruction data more thoroughly
            pass

        return jsonify({
            "signature": signature,
            "slot": tx_data.slot,
            "block_time": tx_data.block_time,
            "success": tx_data.meta.err is None if tx_data.meta else False,
            "fee": tx_data.meta.fee if tx_data.meta else 0,
            "token_transfers": token_transfers
        })
    except Exception as e:
        if "not found" in str(e).lower() or "does not exist" in str(e).lower():
            return jsonify({"error": "Transaction not found"}), 404
        return jsonify({"error": str(e)}), 500

@app.route('/account/<address>')
def get_account(address):
    try:
        # Get account info
        pubkey = PublicKey(address)
        account_info = client.get_account_info(pubkey)

        if not account_info.value:
            # Return default account structure for non-existent accounts
            return jsonify({
                "address": address,
                "executable": False,
                "lamports": 0,
                "owner": "11111111111111111111111111111111",
                "rent_epoch": 0
            })

        account = account_info.value

        return jsonify({
            "address": address,
            "executable": account.executable,
            "lamports": account.lamports,
            "owner": str(account.owner),
            "rent_epoch": account.rent_epoch
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/program/<program_id>/accounts')
def get_program_accounts(program_id):
    try:
        # Get pagination parameters
        limit = min(int(request.args.get('limit', 10)), 100)  # Cap at 100
        offset = int(request.args.get('offset', 0))

        # Get accounts owned by program
        program_pubkey = PublicKey(program_id)
        accounts = client.get_program_accounts(program_pubkey)

        if not accounts.value:
            return jsonify({
                "program_id": program_id,
                "total_accounts": 0,
                "limit": limit,
                "offset": offset,
                "accounts": []
            })

        all_accounts = accounts.value
        total_accounts = len(all_accounts)

        # Apply pagination
        paginated_accounts = all_accounts[offset:offset + limit]

        account_list = []
        for acc in paginated_accounts:
            account_list.append({
                "pubkey": str(acc.pubkey),
                "account": {
                    "executable": acc.account.executable,
                    "lamports": acc.account.lamports,
                    "owner": str(acc.account.owner),
                    "rent_epoch": acc.account.rent_epoch
                }
            })

        return jsonify({
            "program_id": program_id,
            "total_accounts": total_accounts,
            "limit": limit,
            "offset": offset,
            "accounts": account_list
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)
